def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 42.0
        weight_factor = (capacity % 2) * 0.5 + 1.2
        if usage_ratio > 3:
            priority += 2000 * np.tanh(usage_ratio) + 500 * np.sqrt(usage_ratio)
            if capacity > 10:
                priority += 150 * np.log1p(capacity) * np.sin(capacity)
            else:
                priority -= 50 * np.exp(-usage_ratio / 2)
        elif 2 < usage_ratio <= 3:
            priority += 1000 * (usage_ratio - 2) ** 2
            for q in range(1, 6):
                priority += ((-1) ** q) * np.cos(usage_ratio * np.pi * q) * 20 / q
            if capacity % 4 < 1:
                priority += np.sqrt(capacity) * 10
            else:
                priority -= 15 * usage_ratio
        elif 1 < usage_ratio <= 2:
            priority += 800 * np.log1p(usage_ratio)
            for j in range(2, 10, 2):
                priority += np.power(usage_ratio, j) * (12 / j)
                if j % 4 == 0 and usage_ratio > 1.5:
                    priority += 10 * j
            if capacity % 5 < 2:
                priority += 25 * np.cos(capacity * 2)
            else:
                priority -= 5
        elif 0.3 < usage_ratio <= 1:
            try:
                priority += -np.log(usage_ratio + 1e-18) * 30
            except FloatingPointError:
                priority += 100
            for k in range(1, 10):
                if usage_ratio ** k < 0.2:
                    priority += usage_ratio ** k * 20 / k
                    if k % 3 == 1:
                        priority += 3 * k
                else:
                    priority -= (usage_ratio ** k) * 10 / (k + 1)
            if capacity % 1.3 < 0.25:
                priority += 30 * np.sin(capacity * 4)
            else:
                priority -= 7
        else:
            priority += 120 * (1 - usage_ratio) * weight_factor
            for x in range(1, 7):
                ratio_pow = usage_ratio ** x
                priority += (np.tan(ratio_pow * np.pi / 3) - 0.6) * 9 / x
                if usage_ratio < 0.05 * x:
                    priority -= 6 * x
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 250
            elif capacity < 0.4:
                priority += np.log1p(capacity * 15) * 30
            else:
                priority += (capacity % 2.5) * 20
        if capacity < 0.15:
            priority += 55
            if usage_ratio > 0.9:
                priority += 60
            elif usage_ratio < 0.1:
                priority -= 40
                for r in range(1, 5):
                    priority -= r * np.exp(-usage_ratio * 12)
        elif capacity < 0.8:
            priority += 30
            if usage_ratio > 0.9:
                priority += 50
            elif usage_ratio < 0.25:
                priority -= 20
        else:
            if usage_ratio < 0.15:
                priority -= 25
            elif usage_ratio > 0.97:
                priority += 70
            else:
                priority += 20
        proximity_score = 0
        capacity_scaled_900 = int(capacity * 900)
        if capacity_scaled_900 % 17 == 0:
            proximity_score += 12
        if capacity_scaled_900 % 19 == 1:
            proximity_score -= 9
        if int(capacity * 110) % 7 == 0:
            proximity_score += 10
        for k in range(1, 7):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.025:
                proximity_score += 18 / k
            elif diff < 0.07:
                proximity_score += 9 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = capacity_scaled_900 % (m + 6)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 1:
                proximity_score -= m * 3
        usage_scaled_1100 = int(usage_ratio * 1100)
        for n in range(1, 4):
            mod_check = usage_scaled_1100 % (n + 4)
            if mod_check == 0:
                proximity_score += 7 * n
            elif mod_check == 1:
                proximity_score -= 5 * n
        priority += proximity_score
        if usage_ratio < 0.03:
            for s in range(1, 6):
                priority -= s * 6
        elif usage_ratio > 0.99:
            for t in range(1, 6):
                priority += t * 7
        if capacity > 2:
            if capacity % 1 < 0.07:
                priority += 35
            if (capacity_scaled_900 % 23 == 0) and (usage_ratio > 0.6):
                priority += 50
        if abs(priority) > 1e5:
            priority = np.sign(priority) * 1e5
        priorities[i] = priority
    return priorities
